from collections import namedtuple


Server = namedtuple('Server', ['host', 'port', 'timeout'])


def default_config():
    # BUG: tuple is immutable but caller tries to mutate
    return ('localhost', 8080, 30)


def update_config(cfg, key, value):
    # expects dict-like, but we return tuple
    idx = {'host': 0, 'port': 1, 'timeout': 2}[key]
    cfg[idx] = value
    return cfg


def main():
    cfg = default_config()
    update_config(cfg, 'port', 9000)
    print(cfg)


if __name__ == '__main__':
    main()
